// job.js
// Um job descreve o que gerar, com qual template e com quais dados.
// A chave de idempotência deve ser derivada do contexto do negócio (ex.: invoiceId).

export function buildPdfJob({ idempotencyKey, templateVersion, payload }) {
  return {
    jobId: idempotencyKey,
    templateVersion,
    schemaVersion: 1,
    createdAt: new Date().toISOString(),
    payload,
  };
}

export function hashPayload(payload) {
  // Evite dependências externas; use crypto do Node.
  // Normalize strings antes, se necessário.
  const { createHash } = await import('node:crypto');
  return createHash('sha256').update(JSON.stringify(payload)).digest('hex');
}

// api.js
// Exemplo simplificado: valida payload, cria job idempotente, enfileira.

import { buildPdfJob } from './job.js';

export async function requestPdf(req, res, { queue, validatePayload }) {
  const businessId = req.params.id; // ex.: invoiceId
  const payload = req.body;

  const result = validatePayload(payload);
  if (!result.ok) {
    return res.status(400).json({ error: 'invalid_payload', details: result.errors });
  }

  const job = buildPdfJob({
    idempotencyKey: `invoice:${businessId}`,
    templateVersion: 'v1',
    payload,
  });

  // Enfileire com deduplicação por jobId, se sua infra permitir.
  await queue.enqueue(job.jobId, job);

  // Retorne um identificador; o cliente consulta status ou recebe callback/webhook.
  return res.status(202).json({ jobId: job.jobId, status: 'queued' });
}

// worker.js
// Render genérico com timeout e classificação de erro.

function withTimeout(promise, ms) {
  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), ms);
  return {
    signal: controller.signal,
    run: promise.finally(() => clearTimeout(t)),
  };
}

function classifyError(err) {
  // Exemplo: ajuste conforme seu motor/infra.
  const msg = String(err?.message || err);
  if (msg.includes('ETIMEDOUT') || msg.includes('ECONNRESET')) return 'transient';
  if (msg.includes('font') || msg.includes('template')) return 'permanent';
  return 'unknown';
}

export async function processJob(job, { renderer, storage, logger }) {
  const startedAt = Date.now();
  logger.info({ jobId: job.jobId, templateVersion: job.templateVersion }, 'pdf_job_started');

  try {
    // renderer.render deve retornar um Buffer (bytes do PDF)
    const { signal, run } = withTimeout(renderer.render(job, { signal }), 30_000);
    const pdfBuffer = await run;

    const key = `pdf/${job.jobId}/${job.templateVersion}.pdf`;
    await storage.put(key, pdfBuffer, {
      contentType: 'application/pdf',
      metadata: {
        jobId: job.jobId,
        templateVersion: job.templateVersion,
        schemaVersion: String(job.schemaVersion),
      },
    });

    logger.info(
      { jobId: job.jobId, ms: Date.now() - startedAt, bytes: pdfBuffer.length },
      'pdf_job_succeeded'
    );

    return { ok: true, key };
  } catch (err) {
    const kind = classifyError(err);
    logger.error(
      { jobId: job.jobId, kind, ms: Date.now() - startedAt, err: String(err?.message || err) },
      'pdf_job_failed'
    );

    return { ok: false, kind };
  }
}
